1	<?php
2	
3	namespace Illuminate\Queue;
4	
5	use Illuminate\Contracts\Cache\Repository as CacheContract;
6	use Illuminate\Contracts\Debug\ExceptionHandler;
7	use Illuminate\Contracts\Events\Dispatcher;
8	use Illuminate\Contracts\Queue\Factory as QueueManager;
9	use Illuminate\Contracts\Queue\Interruptible;
10	use Illuminate\Database\DetectsLostConnections;
11	use Illuminate\Queue\Events\JobAttempted;
12	use Illuminate\Queue\Events\JobExceptionOccurred;
13	use Illuminate\Queue\Events\JobPopped;
14	use Illuminate\Queue\Events\JobPopping;
15	use Illuminate\Queue\Events\JobProcessed;
16	use Illuminate\Queue\Events\JobProcessing;
17	use Illuminate\Queue\Events\JobReleasedAfterException;
18	use Illuminate\Queue\Events\JobTimedOut;
19	use Illuminate\Queue\Events\Looping;
20	use Illuminate\Queue\Events\WorkerIdle;
21	use Illuminate\Queue\Events\WorkerInterrupted;
22	use Illuminate\Queue\Events\WorkerPausing;
23	use Illuminate\Queue\Events\WorkerResuming;
24	use Illuminate\Queue\Events\WorkerStarting;
25	use Illuminate\Queue\Events\WorkerStopping;
26	use Illuminate\Support\Carbon;
27	use Throwable;
28	
29	class Worker
30	{
31	    use DetectsLostConnections;
32	
33	    const EXIT_SUCCESS = 0;
34	    const EXIT_ERROR = 1;
35	    const EXIT_MEMORY_LIMIT = 12;
36	
37	    /**
38	     * The name of the worker.
39	     *
40	     * @var string|null
41	     */
42	    protected $name;
43	
44	    /**
45	     * The queue manager instance.
46	     *
47	     * @var \Illuminate\Contracts\Queue\Factory
48	     */
49	    protected $manager;
50	
51	    /**
52	     * The event dispatcher instance.
53	     *
54	     * @var \Illuminate\Contracts\Events\Dispatcher
55	     */
56	    protected $events;
57	
58	    /**
59	     * The cache repository implementation.
60	     *
61	     * @var \Illuminate\Contracts\Cache\Repository
62	     */
63	    protected $cache;
64	
65	    /**
66	     * The exception handler instance.
67	     *
68	     * @var \Illuminate\Contracts\Debug\ExceptionHandler
69	     */
70	    protected $exceptions;
71	
72	    /**
73	     * The callback used to determine if the application is in maintenance mode.
74	     *
75	     * @var callable
76	     */
77	    protected $isDownForMaintenance;
78	
79	    /**
80	     * The callback used to reset the application's scope.
81	     *
82	     * @var callable
83	     */
84	    protected $resetScope;
85	
86	    /**
87	     * The job currently being processed.
88	     *
89	     * @var \Illuminate\Contracts\Queue\Job|null
90	     */
91	    public $currentJob = null;
92	
93	    /**
94	     * Indicates if the worker should exit.
95	     *
96	     * @var bool
97	     */
98	    public $shouldQuit = false;
99	
100	    /**
101	     * Indicates if the worker lost its connection.
102	     *
103	     * @var bool
104	     */
105	    public $lostConnection = false;
106	
107	    /**
108	     * Indicates if the worker is paused.
109	     *
110	     * @var bool
111	     */
112	    public $paused = false;
113	
114	    /**
115	     * The callbacks used to pop jobs from queues.
116	     *
117	     * @var callable[]
118	     */
119	    protected static $popCallbacks = [];
120	
121	    /**
122	     * The custom exit code to be used when memory is exceeded.
123	     *
124	     * @var int|null
125	     */
126	    public static $memoryExceededExitCode;
127	
128	    /**
129	     * The custom exit code to be used when a job times out.
130	     *
131	     * @var int|null
132	     */
133	    public static $timedOutExitCode;
134	
135	    /**
136	     * Indicates if the worker should report job exceptions.
137	     *
138	     * @var bool
139	     */
140	    public static $reportJobExceptions = true;
141	
142	    /**
143	     * Indicates if the worker should stop when a lost connection is detected.
144	     *
145	     * @var bool
146	     */
147	    public static $stopOnLostConnection = true;
148	
149	    /**
150	     * Indicates if the worker should check for the restart signal in the cache.
151	     *
152	     * @var bool
153	     */
154	    public static $restartable = true;
155	
156	    /**
157	     * Indicates if the worker should check for the paused signal in the cache.
158	     *
159	     * @var bool
160	     */
161	    public static $pausable = true;
162	
163	    /**
164	     * Create a new queue worker.
165	     *
166	     * @param  \Illuminate\Contracts\Queue\Factory  $manager
167	     * @param  \Illuminate\Contracts\Events\Dispatcher  $events
168	     * @param  \Illuminate\Contracts\Debug\ExceptionHandler  $exceptions
169	     * @param  callable  $isDownForMaintenance
170	     * @param  callable|null  $resetScope
171	     */
172	    public function __construct(
173	        QueueManager $manager,
174	        Dispatcher $events,
175	        ExceptionHandler $exceptions,
176	        callable $isDownForMaintenance,
177	        ?callable $resetScope = null,
178	    ) {
179	        $this->events = $events;
180	        $this->manager = $manager;
181	        $this->exceptions = $exceptions;
182	        $this->isDownForMaintenance = $isDownForMaintenance;
183	        $this->resetScope = $resetScope;
184	    }
185	
186	    /**
187	     * Listen to the given queue in a loop.
188	     *
189	     * @param  string  $connectionName
190	     * @param  string  $queue
191	     * @param  \Illuminate\Queue\WorkerOptions  $options
192	     * @return int
193	     */
194	    public function daemon($connectionName, $queue, WorkerOptions $options)
195	    {
196	        if ($supportsAsyncSignals = $this->supportsAsyncSignals()) {
197	            $this->listenForSignals($connectionName, $queue, $options);
198	        }
199	
200	        $lastRestart = $this->getTimestampOfLastQueueRestart();
201	
202	        [$startTime, $jobsProcessed] = [$this->currentTime(), 0];
203	
204	        $lastJobProcessedAt = $startTime;
205	
206	        $this->raiseWorkerStartingEvent($connectionName, $queue, $options);
207	
208	        while (true) {
209	            // Before reserving any jobs, we will make sure this queue is not paused and
210	            // if it is we will just pause this worker for a given amount of time and
211	            // make sure we do not need to kill this worker process off completely.
212	            if (! $this->daemonShouldRun($options, $connectionName, $queue)) {
213	                [$status, $reason] = $this->pauseWorker(
214	                    $options, $lastRestart, $startTime, $jobsProcessed, $lastJobProcessedAt
215	                );
216	
217	                if (! is_null($status)) {
218	                    return $this->stop($status, $options, $reason);
219	                }
220	
221	                continue;
222	            }
223	
224	            if (isset($this->resetScope)) {
225	                ($this->resetScope)();
226	            }
227	
228	            // First, we will attempt to get the next job off of the queue. We will also
229	            // register the timeout handler and reset the alarm for this job so it is
230	            // not stuck in a frozen state forever. Then, we can fire off this job.
231	            $job = $this->getNextJob(
232	                $this->manager->connection($connectionName), $queue
233	            );
234	
235	            if ($supportsAsyncSignals) {
236	                $this->registerTimeoutHandler($job, $options);
237	            }
238	
239	            // If the daemon should run (not in maintenance mode, etc.), then we can run
240	            // fire off this job for processing. Otherwise, we will need to sleep the
241	            // worker so no more jobs are processed until they should be processed.
242	            if ($job) {
243	                $jobsProcessed++;
244	
245	                $this->runJob($job, $connectionName, $options);
246	
247	                $lastJobProcessedAt = $this->currentTime();
248	
249	                if ($options->rest > 0) {
250	                    $this->sleep($options->rest);
251	                }
252	            } else {
253	                $this->events->dispatch(new WorkerIdle($connectionName, $queue, $options));
254	
255	                $this->sleep($options->sleep);
256	            }
257	
258	            if ($supportsAsyncSignals) {
259	                $this->resetTimeoutHandler();
260	            }
261	
262	            // Finally, we will check to see if we have exceeded our memory limits or if
263	            // the queue should restart based on other indications. If so, we'll stop
264	            // this worker and let whatever is "monitoring" it restart the process.
265	            [$status, $reason] = $this->stopIfNecessary(
266	                $options, $lastRestart, $startTime, $jobsProcessed, $job, $lastJobProcessedAt
267	            );
268	
269	            if (! is_null($status)) {
270	                return $this->stop($status, $options, $reason);
271	            }
272	        }
273	    }
274	
275	    /**
276	     * Register the worker timeout handler.
277	     *
278	     * @param  \Illuminate\Contracts\Queue\Job|null  $job
279	     * @param  \Illuminate\Queue\WorkerOptions  $options
280	     * @return void
281	     */
282	    protected function registerTimeoutHandler($job, WorkerOptions $options)
283	    {
284	        // We will register a signal handler for the alarm signal so that we can kill this
285	        // process if it is running too long because it has frozen. This uses the async
286	        // signals supported in recent versions of PHP to accomplish it conveniently.
287	        pcntl_signal(SIGALRM, function () use ($job, $options) {
288	            if ($job) {
289	                $this->markJobAsFailedIfWillExceedMaxAttempts(
290	                    $job->getConnectionName(), $job, (int) $options->maxTries, $e = $this->timeoutExceededException($job)
291	                );
292	
293	                $this->markJobAsFailedIfWillExceedMaxExceptions(
294	                    $job->getConnectionName(), $job, $e
295	                );
296	
297	                $this->markJobAsFailedIfItShouldFailOnTimeout(
298	                    $job->getConnectionName(), $job, $e
299	                );
300	
301	                $this->events->dispatch(new JobTimedOut(
302	                    $job->getConnectionName(), $job
303	                ));
304	            }
305	
306	            $this->kill(static::$timedOutExitCode ?? static::EXIT_ERROR, $options, WorkerStopReason::TimedOut);
307	        }, true);
308	
309	        pcntl_alarm(
310	            max($this->timeoutForJob($job, $options), 0)
311	        );
312	    }
313	
314	    /**
315	     * Reset the worker timeout handler.
316	     *
317	     * @return void
318	     */
319	    protected function resetTimeoutHandler()
320	    {
321	        pcntl_alarm(0);
322	    }
323	
324	    /**
325	     * Get the appropriate timeout for the given job.
326	     *
327	     * @param  \Illuminate\Contracts\Queue\Job|null  $job
328	     * @param  \Illuminate\Queue\WorkerOptions  $options
329	     * @return int
330	     */
331	    protected function timeoutForJob($job, WorkerOptions $options)
332	    {
333	        return $job && ! is_null($job->timeout()) ? $job->timeout() : $options->timeout;
334	    }
335	
336	    /**
337	     * Determine if the daemon should process on this iteration.
338	     *
339	     * @param  \Illuminate\Queue\WorkerOptions  $options
340	     * @param  string  $connectionName
341	     * @param  string  $queue
342	     * @return bool
343	     */
344	    protected function daemonShouldRun(WorkerOptions $options, $connectionName, $queue)
345	    {
346	        return ! ((! $options->force && ($this->isDownForMaintenance)()) ||
347	            $this->paused ||
348	            $this->events->until(new Looping($connectionName, $queue, $options)) === false);
349	    }
350	
351	    /**
352	     * Pause the worker for the current loop.
353	     *
354	     * @param  \Illuminate\Queue\WorkerOptions  $options
355	     * @param  int  $lastRestart
356	     * @param  int|float  $startTime
357	     * @param  int  $jobsProcessed
358	     * @param  int|float|null  $lastJobProcessedAt
359	     * @return array|null
360	     */
361	    protected function pauseWorker(WorkerOptions $options, $lastRestart, $startTime = 0, $jobsProcessed = 0, $lastJobProcessedAt = null)
362	    {
363	        $this->sleep($options->sleep > 0 ? $options->sleep : 1);
364	
365	        return $this->stopIfNecessary($options, $lastRestart, $startTime, $jobsProcessed, null, $lastJobProcessedAt);
366	    }
367	
368	    /**
369	     * Determine the exit code to stop the process if necessary.
370	     *
371	     * @param  \Illuminate\Queue\WorkerOptions  $options
372	     * @param  int  $lastRestart
373	     * @param  int  $startTime
374	     * @param  int  $jobsProcessed
375	     * @param  mixed  $job
376	     * @param  int|float|null  $lastJobProcessedAt
377	     * @return array|null
378	     */
379	    protected function stopIfNecessary(WorkerOptions $options, $lastRestart, $startTime = 0, $jobsProcessed = 0, $job = null, $lastJobProcessedAt = null)
380	    {
381	        return match (true) {
382	            $this->lostConnection => [static::EXIT_SUCCESS, WorkerStopReason::LostConnection],
383	            $this->shouldQuit => [static::EXIT_SUCCESS, WorkerStopReason::Interrupted],
384	            $this->memoryExceeded($options->memory) => [static::$memoryExceededExitCode ?? static::EXIT_MEMORY_LIMIT, WorkerStopReason::MaxMemoryExceeded],
385	            $this->queueShouldRestart($lastRestart) => [static::EXIT_SUCCESS, WorkerStopReason::ReceivedRestartSignal],
386	            $options->stopWhenEmpty && is_null($job) => [static::EXIT_SUCCESS, WorkerStopReason::QueueEmpty],
387	            $options->stopWhenEmptyFor && is_null($job) && $this->currentTime() - ($lastJobProcessedAt ?? $startTime) >= $options->stopWhenEmptyFor => [static::EXIT_SUCCESS, WorkerStopReason::QueueEmptyFor],
388	            $options->maxTime && $this->currentTime() - $startTime >= $options->maxTime => [static::EXIT_SUCCESS, WorkerStopReason::MaxTimeExceeded],
389	            $options->maxJobs && $jobsProcessed >= $options->maxJobs => [static::EXIT_SUCCESS, WorkerStopReason::MaxJobsExceeded],
390	            default => null
391	        };
392	    }
393	
394	    /**
395	     * Process the next job on the queue.
396	     *
397	     * @param  string  $connectionName
398	     * @param  string  $queue
399	     * @param  \Illuminate\Queue\WorkerOptions  $options
400	     * @return void
401	     */
402	    public function runNextJob($connectionName, $queue, WorkerOptions $options)
403	    {
404	        $job = $this->getNextJob(
405	            $this->manager->connection($connectionName), $queue
406	        );
407	
408	        // If we're able to pull a job off of the stack, we will process it and then return
409	        // from this method. If there is no job on the queue, we will "sleep" the worker
410	        // for the specified number of seconds, then keep processing jobs after sleep.
411	        if ($job) {
412	            return $this->runJob($job, $connectionName, $options);
413	        }
414	
415	        $this->sleep($options->sleep);
416	    }
417	
418	    /**
419	     * Get the next job from the queue connection.
420	     *
421	     * @param  \Illuminate\Contracts\Queue\Queue  $connection
422	     * @param  string  $queue
423	     * @return \Illuminate\Contracts\Queue\Job|null
424	     */
425	    protected function getNextJob($connection, $queue)
426	    {
427	        $popJobCallback = function ($queue, $index = 0) use ($connection) {
428	            return $connection->pop($queue, $index);
429	        };
430	
431	        $this->raiseBeforeJobPopEvent($connection->getConnectionName(), $queue);
432	
433	        try {
434	            if (isset(static::$popCallbacks[$this->name ?? ''])) {
435	                if (! is_null($job = (static::$popCallbacks[$this->name ?? ''])($popJobCallback, $queue))) {
436	                    $this->raiseAfterJobPopEvent($connection->getConnectionName(), $job);
437	                }
438	
439	                return $job;
440	            }
441	
442	            $queues = explode(',', $queue);
443	
444	            $paused = array_flip($this->getPausedQueues($connection->getConnectionName(), $queues));
445	
446	            foreach ($queues as $index => $queue) {
447	                if (isset($paused[$queue])) {
448	                    continue;
449	                }
450	
451	                if (! is_null($job = $popJobCallback($queue, $index))) {
452	                    $this->raiseAfterJobPopEvent($connection->getConnectionName(), $job);
453	
454	                    return $job;
455	                }
456	            }
457	        } catch (Throwable $e) {
458	            $this->exceptions->report($e);
459	
460	            $this->stopWorkerIfLostConnection($e);
461	
462	            $this->sleep(1);
463	        }
464	    }
465	
466	    /**
467	     * Determine which of the given queues are currently paused.
468	     *
469	     * @param  string  $connectionName
470	     * @param  array  $queues
471	     * @return array
472	     */
473	    protected function getPausedQueues($connectionName, $queues)
474	    {
475	        if (! static::$pausable) {
476	            return [];
477	        }
478	
479	        if ($this->cache === null) {
480	            return [];
481	        }
482	
483	        return $this->manager->getPausedQueues($connectionName, $queues);
484	    }
485	
486	    /**
487	     * Process the given job.
488	     *
489	     * @param  \Illuminate\Contracts\Queue\Job  $job
490	     * @param  string  $connectionName
491	     * @param  \Illuminate\Queue\WorkerOptions  $options
492	     * @return void
493	     */
494	    protected function runJob($job, $connectionName, WorkerOptions $options)
495	    {
496	        $this->currentJob = $job;
497	
498	        try {
499	            return $this->process($connectionName, $job, $options);
500	        } catch (Throwable $e) {
501	            if (static::$reportJobExceptions) {
502	                $this->exceptions->report($e);
503	            }
504	
505	            $this->stopWorkerIfLostConnection($e);
506	        } finally {
507	            $this->currentJob = null;
508	        }
509	    }
510	
511	    /**
512	     * Stop the worker if we have lost connection to a database.
513	     *
514	     * @param  \Throwable  $e
515	     * @return void
516	     */
517	    protected function stopWorkerIfLostConnection($e)
518	    {
519	        if (static::$stopOnLostConnection && $this->causedByLostConnection($e)) {
520	            $this->lostConnection = true;
521	        }
522	    }
523	
524	    /**
525	     * Process the given job from the queue.
526	     *
527	     * @param  string  $connectionName
528	     * @param  \Illuminate\Contracts\Queue\Job  $job
529	     * @param  \Illuminate\Queue\WorkerOptions  $options
530	     * @return void
531	     *
532	     * @throws \Throwable
533	     */
534	    public function process($connectionName, $job, WorkerOptions $options)
535	    {
536	        try {
537	            // First we will raise the before job event and determine if the job has already run
538	            // over its maximum attempt limits, which could primarily happen when this job is
539	            // continually timing out and not actually throwing any exceptions from itself.
540	            $this->raiseBeforeJobEvent($connectionName, $job);
541	
542	            $this->markJobAsFailedIfAlreadyExceedsMaxAttempts(
543	                $connectionName, $job, (int) $options->maxTries
544	            );
545	
546	            if ($job->isDeleted()) {
547	                return $this->raiseAfterJobEvent($connectionName, $job);
548	            }
549	
550	            // Here we will fire off the job and let it process. We will catch any exceptions, so
551	            // they can be reported to the developer's logs, etc. Once the job is finished the
552	            // proper events will be fired to let any listeners know this job has completed.
553	            $job->fire();
554	
555	            $this->raiseAfterJobEvent($connectionName, $job);
556	        } catch (Throwable $e) {
557	            $exceptionOccurred = $e;
558	
559	            $this->handleJobException($connectionName, $job, $options, $e);
560	        } finally {
561	            $this->events->dispatch(new JobAttempted(
562	                $connectionName, $job, $exceptionOccurred ?? null
563	            ));
564	        }
565	    }
566	
567	    /**
568	     * Handle an exception that occurred while the job was running.
569	     *
570	     * @param  string  $connectionName
571	     * @param  \Illuminate\Contracts\Queue\Job  $job
572	     * @param  \Illuminate\Queue\WorkerOptions  $options
573	     * @param  \Throwable  $e
574	     * @return void
575	     *
576	     * @throws \Throwable
577	     */
578	    protected function handleJobException($connectionName, $job, WorkerOptions $options, Throwable $e)
579	    {
580	        try {
581	            // First, we will go ahead and mark the job as failed if it will exceed the maximum
582	            // attempts it is allowed to run the next time we process it. If so we will just
583	            // go ahead and mark it as failed now so we do not have to release this again.
584	            if (! $job->hasFailed()) {
585	                $this->markJobAsFailedIfWillExceedMaxAttempts(
586	                    $connectionName, $job, (int) $options->maxTries, $e
587	                );
588	
589	                $this->markJobAsFailedIfWillExceedMaxExceptions(
590	                    $connectionName, $job, $e
591	                );
592	
593	                $this->markJobAsFailedIfItShouldntBeRetried(
594	                    $connectionName, $job, $e
595	                );
596	            }
597	
598	            $this->raiseExceptionOccurredJobEvent(
599	                $connectionName, $job, $e
600	            );
601	        } finally {
602	            // If we catch an exception, we will attempt to release the job back onto the queue
603	            // so it is not lost entirely. This'll let the job be retried at a later time by
604	            // another listener (or this same one). We will re-throw this exception after.
605	            if (! $job->isDeleted() && ! $job->isReleased() && ! $job->hasFailed()) {
606	                $backoff = $this->calculateBackoff($job, $options);
607	
608	                $job->release($backoff);
609	
610	                $this->events->dispatch(new JobReleasedAfterException(
611	                    $connectionName, $job, $backoff
612	                ));
613	            }
614	        }
615	
616	        throw $e;
617	    }
618	
619	    /**
620	     * Mark the given job as failed if it has exceeded the maximum allowed attempts.
621	     *
622	     * This will likely be because the job previously exceeded a timeout.
623	     *
624	     * @param  string  $connectionName
625	     * @param  \Illuminate\Contracts\Queue\Job  $job
626	     * @param  int  $maxTries
627	     * @return void
628	     *
629	     * @throws \Throwable
630	     */
631	    protected function markJobAsFailedIfAlreadyExceedsMaxAttempts($connectionName, $job, $maxTries)
632	    {
633	        $maxTries = ! is_null($job->maxTries()) ? $job->maxTries() : $maxTries;
634	
635	        $retryUntil = $job->retryUntil();
636	
637	        if ($retryUntil && Carbon::now()->getTimestamp() <= $retryUntil) {
638	            return;
639	        }
640	
641	        if (! $retryUntil && ($maxTries === 0 || $job->attempts() <= $maxTries)) {
642	            return;
643	        }
644	
645	        $this->failJob($job, $e = $this->maxAttemptsExceededException($job));
646	
647	        throw $e;
648	    }
649	
650	    /**
651	     * Mark the given job as failed if it has exceeded the maximum allowed attempts.
652	     *
653	     * @param  string  $connectionName
654	     * @param  \Illuminate\Contracts\Queue\Job  $job
655	     * @param  int  $maxTries
656	     * @param  \Throwable  $e
657	     * @return void
658	     */
659	    protected function markJobAsFailedIfWillExceedMaxAttempts($connectionName, $job, $maxTries, Throwable $e)
660	    {
661	        $maxTries = ! is_null($job->maxTries()) ? $job->maxTries() : $maxTries;
662	
663	        if ($job->retryUntil() && $job->retryUntil() <= Carbon::now()->getTimestamp()) {
664	            $this->failJob($job, $e);
665	        }
666	
667	        if (! $job->retryUntil() && $maxTries > 0 && $job->attempts() >= $maxTries) {
668	            $this->failJob($job, $e);
