3	namespace Illuminate\Queue;
4	
5	use Exception;
6	use Illuminate\Bus\Batchable;
7	use Illuminate\Bus\BatchRepository;
8	use Illuminate\Bus\DebounceLock;
9	use Illuminate\Bus\UniqueLock;
10	use Illuminate\Contracts\Bus\Dispatcher;
11	use Illuminate\Contracts\Cache\Factory as CacheFactory;
12	use Illuminate\Contracts\Cache\Repository as Cache;
13	use Illuminate\Contracts\Container\Container;
14	use Illuminate\Contracts\Encryption\Encrypter;
15	use Illuminate\Contracts\Queue\Job;
16	use Illuminate\Contracts\Queue\ShouldBeUnique;
17	use Illuminate\Contracts\Queue\ShouldBeUniqueUntilProcessing;
18	use Illuminate\Database\Eloquent\ModelNotFoundException;
19	use Illuminate\Events\CallQueuedListener;
20	use Illuminate\Log\Context\Repository as ContextRepository;
21	use Illuminate\Pipeline\Pipeline;
22	use Illuminate\Queue\Events\JobDebounced;
23	use RuntimeException;
24	
25	class CallQueuedHandler
26	{
27	    /**
28	     * The bus dispatcher implementation.
29	     *
30	     * @var \Illuminate\Contracts\Bus\Dispatcher
31	     */
32	    protected $dispatcher;
33	
34	    /**
35	     * The container instance.
36	     *
37	     * @var \Illuminate\Contracts\Container\Container
38	     */
39	    protected $container;
40	
41	    /**
42	     * The command currently being processed.
43	     *
44	     * @var mixed
45	     */
46	    protected $runningCommand;
47	
48	    /**
49	     * Create a new handler instance.
50	     *
51	     * @param  \Illuminate\Contracts\Bus\Dispatcher  $dispatcher
52	     * @param  \Illuminate\Contracts\Container\Container  $container
53	     */
54	    public function __construct(Dispatcher $dispatcher, Container $container)
55	    {
56	        $this->container = $container;
57	        $this->dispatcher = $dispatcher;
58	    }
59	
60	    /**
61	     * Handle the queued job.
62	     *
63	     * @param  \Illuminate\Contracts\Queue\Job  $job
64	     * @param  array  $data
65	     * @return void
66	     */
67	    public function call(Job $job, array $data)
68	    {
69	        try {
70	            $command = $this->setJobInstanceIfNecessary(
71	                $job, $this->getCommand($data)
72	            );
73	        } catch (ModelNotFoundException $e) {
74	            return $this->handleModelNotFound($job, $e);
75	        }
76	
77	        if ($this->commandShouldBeDebounced($command)) {
78	            return $this->deleteDebouncedJob($job, $command);
79	        }
80	
81	        $this->runningCommand = $command;
82	
83	        try {
84	            $this->dispatchThroughMiddleware($job, $command);
85	        } finally {
86	            $this->runningCommand = null;
87	        }
88	
89	        if (! $job->isReleased() && ! $this->commandShouldBeUniqueUntilProcessing($command)) {
90	            $this->ensureUniqueJobLockIsReleased($command);
91	        }
92	
93	        if (! $job->hasFailed() && ! $job->isReleased()) {
94	            $this->ensureNextJobInChainIsDispatched($command);
95	            $this->ensureSuccessfulBatchJobIsRecorded($command);
96	        }
97	
98	        if (! $job->isDeletedOrReleased()) {
99	            $job->delete();
100	        }
101	    }
102	
103	    /**
104	     * Get the command from the given payload.
105	     *
106	     * @param  array  $data
107	     * @return mixed
108	     *
109	     * @throws \RuntimeException
110	     */
111	    protected function getCommand(array $data)
112	    {
113	        if (str_starts_with($data['command'], 'O:')) {
114	            return unserialize($data['command']);
115	        }
116	
117	        if ($this->container->bound(Encrypter::class)) {
118	            return unserialize($this->container[Encrypter::class]->decrypt($data['command']));
119	        }
120	
121	        throw new RuntimeException('Unable to extract job payload.');
122	    }
123	
124	    /**
125	     * Dispatch the given job / command through its specified middleware.
126	     *
127	     * @param  \Illuminate\Contracts\Queue\Job  $job
128	     * @param  mixed  $command
129	     * @return mixed
130	     */
131	    protected function dispatchThroughMiddleware(Job $job, $command)
132	    {
133	        if ($command instanceof \__PHP_Incomplete_Class) {
134	            throw new Exception('Job is incomplete class: '.json_encode($command));
135	        }
136	
137	        $lockReleased = false;
138	
139	        return (new Pipeline($this->container))->send($command)
140	            ->through(array_merge(method_exists($command, 'middleware') ? $command->middleware() : [], $command->middleware ?? []))
141	            ->finally(function ($command) use (&$lockReleased) {
142	                if (! $lockReleased && $this->commandShouldBeUniqueUntilProcessing($command) && ! $command->job->isReleased() && $command->job->attempts() <= 1) {
143	                    $this->ensureUniqueJobLockIsReleased($command);
144	                }
145	            })
146	            ->then(function ($command) use ($job, &$lockReleased) {
147	                if ($this->commandShouldBeUniqueUntilProcessing($command) && $job->attempts() <= 1) {
148	                    $this->ensureUniqueJobLockIsReleased($command);
149	
150	                    $lockReleased = true;
151	                }
152	
153	                return $this->dispatcher->dispatchNow(
154	                    $command, $this->resolveHandler($job, $command)
155	                );
156	            });
157	    }
158	
159	    /**
160	     * Resolve the handler for the given command.
161	     *
162	     * @param  \Illuminate\Contracts\Queue\Job  $job
163	     * @param  mixed  $command
164	     * @return mixed
165	     */
166	    protected function resolveHandler($job, $command)
167	    {
168	        $handler = $this->dispatcher->getCommandHandler($command) ?: null;
169	
170	        if ($handler) {
171	            $this->setJobInstanceIfNecessary($job, $handler);
172	        }
173	
174	        return $handler;
175	    }
176	
177	    /**
178	     * Set the job instance of the given class if necessary.
179	     *
180	     * @param  \Illuminate\Contracts\Queue\Job  $job
181	     * @param  mixed  $instance
182	     * @return mixed
183	     */
184	    protected function setJobInstanceIfNecessary(Job $job, $instance)
185	    {
186	        if (isset(class_uses_recursive($instance)[InteractsWithQueue::class])) {
187	            $instance->setJob($job);
188	        }
189	
190	        return $instance;
191	    }
192	
193	    /**
194	     * Ensure the next job in the chain is dispatched if applicable.
195	     *
196	     * @param  mixed  $command
197	     * @return void
198	     */
199	    protected function ensureNextJobInChainIsDispatched($command)
200	    {
201	        if (method_exists($command, 'dispatchNextJobInChain')) {
202	            $command->dispatchNextJobInChain();
203	        }
204	    }
205	
206	    /**
207	     * Ensure the batch is notified of the successful job completion.
208	     *
209	     * @param  mixed  $command
210	     * @return void
211	     */
212	    protected function ensureSuccessfulBatchJobIsRecorded($command)
213	    {
214	        $uses = class_uses_recursive($command);
215	
216	        if (! isset($uses[Batchable::class], $uses[InteractsWithQueue::class])) {
217	            return;
218	        }
219	
220	        if ($batch = $command->batch()) {
221	            $batch->recordSuccessfulJob($command->job->uuid());
222	        }
223	    }
224	
225	    /**
226	     * Ensure the lock for a unique job is released.
227	     *
228	     * @param  mixed  $command
229	     * @return void
230	     */
231	    protected function ensureUniqueJobLockIsReleased($command)
232	    {
233	        if ($this->commandShouldBeUnique($command)) {
234	            (new UniqueLock($this->container->make(Cache::class)))->release($command);
235	        }
236	    }
237	
238	    /**
239	     * Determine if the debounced command was superseded by a newer dispatch.
240	     *
241	     * @param  mixed  $command
242	     * @return bool
243	     */
244	    protected function commandShouldBeDebounced($command)
245	    {
246	        $owner = $command->debounceOwner ?? '';
247	
248	        if (empty($owner)) {
249	            return false;
250	        }
251	
252	        $lock = new DebounceLock($this->container->make(Cache::class));
253	
254	        // Fail-open: if the lock no longer exists (cache eviction, TTL expiry), let the job execute...
255	        if (! $lock->lockExists($command)) {
256	            return false;
257	        }
258	
259	        return ! $lock->isCurrentOwner($command, $owner);
260	    }
261	
262	    /**
263	     * Handle a debounced (superseded) job by firing an event and deleting it.
264	     *
265	     * @param  \Illuminate\Contracts\Queue\Job  $job
266	     * @param  mixed  $command
267	     * @return void
268	     */
269	    protected function deleteDebouncedJob($job, $command)
270	    {
271	        if ($this->container->bound('events')) {
272	            $this->container->make('events')->dispatch(
273	                new JobDebounced($job->getConnectionName(), $job, $command)
274	            );
275	        }
276	
277	        $job->delete();
278	    }
279	
280	    /**
281	     * Determine if the given command should be unique.
282	     */
283	    protected function commandShouldBeUnique(mixed $command): bool
284	    {
285	        return $command instanceof ShouldBeUnique ||
286	            ($command instanceof CallQueuedListener && $command->shouldBeUnique());
287	    }
288	
289	    /**
290	     * Determine if the given command should be unique until processing begins.
291	     */
292	    protected function commandShouldBeUniqueUntilProcessing(mixed $command): bool
293	    {
294	        return $command instanceof ShouldBeUniqueUntilProcessing ||
295	            ($command instanceof CallQueuedListener && $command->shouldBeUniqueUntilProcessing());
296	    }
297	
298	    /**
299	     * Handle a model not found exception.
300	     *
301	     * @param  \Illuminate\Contracts\Queue\Job  $job
302	     * @param  \Throwable  $e
303	     * @return void
304	     */
305	    protected function handleModelNotFound(Job $job, $e)
306	    {
307	        $this->ensureUniqueJobLockIsReleasedViaContext();
308	
309	        if ($job->payload()['deleteWhenMissingModels'] ?? false) {
310	            $this->ensureSuccessfulBatchJobIsRecordedForMissingModel($job, $job->resolveQueuedJobClass());
311	
312	            return $job->delete();
313	        }
314	
315	        return $job->fail($e);
316	    }
317	
318	    /**
319	     * Ensure the lock for a unique job is released via context.
320	     *
321	     * This is required when we can't unserialize the job due to missing models.
322	     *
323	     * @return void
324	     */
325	    protected function ensureUniqueJobLockIsReleasedViaContext()
326	    {
327	        if (! $this->container->bound(ContextRepository::class) ||
328	            ! $this->container->bound(CacheFactory::class)) {
329	            return;
330	        }
331	
332	        $context = $this->container->make(ContextRepository::class);
333	
334	        [$store, $key] = [
335	            $context->getHidden('laravel_unique_job_cache_store'),
336	            $context->getHidden('laravel_unique_job_key'),
337	        ];
338	
339	        if ($store && $key) {
340	            $this->container->make(CacheFactory::class)
341	                ->store($store)
342	                ->lock($key)
343	                ->forceRelease();
344	        }
345	    }
346	
347	    /**
348	     * Record a potentially batched job as successful when deleted because models were missing.
349	     *
350	     * @param  \Illuminate\Contracts\Queue\Job  $job
351	     * @param  string  $class
352	     * @return void
353	     */
354	    protected function ensureSuccessfulBatchJobIsRecordedForMissingModel(Job $job, string $class)
355	    {
356	        if (! isset(class_uses_recursive($class)[Batchable::class])) {
357	            return;
358	        }
359	
360	        if (! $this->container->bound(BatchRepository::class)) {
361	            return;
362	        }
363	
364	        $batchId = $job->payload()['data']['batchId'] ?? null;
365	
366	        if ((! is_string($batchId) || $batchId === '') ||
367	             ! is_string($job->uuid()) || $job->uuid() === '') {
368	            return;
369	        }
370	
371	        if ($batch = $this->container->make(BatchRepository::class)->find($batchId)) {
372	            $batch->recordSuccessfulJob($job->uuid());
373	        }
374	    }
375	
376	    /**
377	     * Call the failed method on the job instance.
378	     *
379	     * The exception that caused the failure will be passed.
380	     *
381	     * @param  array  $data
382	     * @param  \Throwable|null  $e
383	     * @param  string  $uuid
384	     * @param  \Illuminate\Contracts\Queue\Job|null  $job
385	     * @return void
386	     */
387	    public function failed(array $data, $e, string $uuid, ?Job $job = null)
388	    {
389	        $command = $this->getCommand($data);
390	
391	        if (! is_null($job)) {
392	            $command = $this->setJobInstanceIfNecessary($job, $command);
393	        }
394	
395	        if (! $this->commandShouldBeUniqueUntilProcessing($command)) {
396	            $this->ensureUniqueJobLockIsReleased($command);
397	        }
398	
399	        if ($command instanceof \__PHP_Incomplete_Class) {
400	            return;
401	        }
402	
403	        $this->ensureFailedBatchJobIsRecorded($uuid, $command, $e);
404	        $this->ensureChainCatchCallbacksAreInvoked($uuid, $command, $e);
405	
406	        if (method_exists($command, 'failed')) {
407	            $command->failed($e);
408	        }
409	    }
410	
411	    /**
412	     * Ensure the batch is notified of the failed job.
413	     *
414	     * @param  string  $uuid
415	     * @param  mixed  $command
416	     * @param  \Throwable  $e
417	     * @return void
418	     */
419	    protected function ensureFailedBatchJobIsRecorded(string $uuid, $command, $e)
420	    {
421	        if (! isset(class_uses_recursive($command)[Batchable::class])) {
422	            return;
423	        }
424	
425	        if ($batch = $command->batch()) {
426	            $batch->recordFailedJob($uuid, $e);
427	        }
428	    }
429	
430	    /**
431	     * Ensure the chained job catch callbacks are invoked.
432	     *
433	     * @param  string  $uuid
434	     * @param  mixed  $command
435	     * @param  \Throwable  $e
436	     * @return void
437	     */
438	    protected function ensureChainCatchCallbacksAreInvoked(string $uuid, $command, $e)
439	    {
440	        if (method_exists($command, 'invokeChainCatchCallbacks')) {
441	            $command->invokeChainCatchCallbacks($e);
442	        }
443	    }
444	
445	    /**
446	     * Get the command currently being processed.
447	     *
448	     * @return mixed
449	     */
450	    public function getRunningCommand()
451	    {
452	        return $this->runningCommand;
453	    }
